			if _, ok := data[core.FieldNamePassword]; !ok {
				data[core.FieldNamePassword] = security.RandomString(30)
				data[core.FieldNamePassword+"Confirm"] = data[core.FieldNamePassword]
				skipPlainPasswordRecordValidators = true
			}
